mapper.select:
SELECT  FROM train_attendance a LEFT JOIN train_plan p ON a.plan_id = p.id LEFT JOIN student s ON a.stu_id = s.id

    AND a.plan_id = #{planId}
    AND a.sign_status = #{signStatus}
    AND a.attend_date = #{attendDate}

ORDER BY a.attend_date DESC, a.create_time DESC

mapper.update:
UPDATE train_attendance
plan_id = #{planId}, stu_id = #{stuId}, attend_date = #{attendDate}, sign_time = #{signTime}, sign_status = #{signStatus}, leave_remark = #{leaveRemark}, update_time = #{updateTime},
WHERE id = #{id}
